import React, { useEffect, useState, useRef } from 'react';

const Dashboard = () => {
  const [stats, setStats] = useState({});
  const [selectedPeriod, setSelectedPeriod] = useState(null);
  const [selectedDay, setSelectedDay] = useState(null);
  const prevPeriodRef = useRef(null);
  const cachedStats = useRef(null);

  const fetchStats = async (period = null, day = null) => {
    // Use cache if period and day not selected (auto mode)
    if (!period && !day && cachedStats.current) {
      setStats(cachedStats.current);
      return;
    }

    const url = `/api/dashboard-stats?${period !== null ? `period=${period}` : ''}${day !== null ? `&day=${day}` : ''}`;
    const res = await fetch(url);
    const data = await res.json();
    setStats(data);

    // Cache the result only in auto mode
    if (!period && !day) {
      cachedStats.current = data;
    }

    // Store current period for auto-tracking
    if (period === null && data.currentPeriod !== -1) {
      prevPeriodRef.current = data.currentPeriod;
    }
  };

  // Auto-fetch on load
  useEffect(() => {
    fetchStats();
  }, []);

  // Auto-update every 5 seconds for period tracking
  useEffect(() => {
    const interval = setInterval(async () => {
      if (selectedPeriod === null) {
        const res = await fetch('/api/dashboard-stats');
        const data = await res.json();

        const currentPeriod = data.currentPeriod;
        if (currentPeriod !== -1 && currentPeriod !== prevPeriodRef.current) {
          console.log(`Period changed to ${currentPeriod + 1}, auto-refreshing stats...`);
          cachedStats.current = null; // Clear previous cache
          fetchStats();
        }
      }
    }, 5000);

    return () => clearInterval(interval);
  }, [selectedPeriod]);

  // Full refresh every ~1 hour
  useEffect(() => {
    const fullRefreshTimer = setInterval(() => {
      console.log('Auto full refresh triggered.');
      cachedStats.current = null;
      fetchStats();
    }, 3595000); // 59 minutes 55 seconds

    return () => clearInterval(fullRefreshTimer);
  }, []);

  const handlePeriodChange = (e) => {
    const period = e.target.value === '' ? null : parseInt(e.target.value);
    setSelectedPeriod(period);
    cachedStats.current = null; // Clear cache if manual change
    fetchStats(period, selectedDay);
  };

  const handleDayChange = (e) => {
    const day = e.target.value === '' ? null : parseInt(e.target.value);
    setSelectedDay(day);
    cachedStats.current = null; // Clear cache if manual change
    fetchStats(selectedPeriod, day);
  };

  return (
    <div className="container mt-4">
      <h1 className="text-center">Dashboard</h1>
      <div className="d-flex justify-content-center align-items-center mb-3">
        <div className="me-3">
          <label htmlFor="period" className="form-label">Period:</label>
          <select id="period" className="form-select" value={selectedPeriod ?? ''} onChange={handlePeriodChange}>
            <option value="">Auto</option>
            {[...Array(7)].map((_, i) => (
              <option key={i} value={i}>Period {i + 1}</option>
            ))}
          </select>
        </div>
        <div className="me-3">
          <label htmlFor="day" className="form-label">Day:</label>
          <select id="day" className="form-select" value={selectedDay ?? ''} onChange={handleDayChange}>
            <option value="">Today</option>
            <option value="0">Monday</option>
            <option value="1">Tuesday</option>
            <option value="2">Wednesday</option>
            <option value="3">Thursday</option>
            <option value="4">Friday</option>
            <option value="5">Saturday</option>
          </select>
        </div>
      </div>
      {stats && (
        <div>
          <p className="text-center text-muted">
            <strong>Current Time:</strong> {stats.time}
            <span className="mx-2">|</span>
            <strong>Period:</strong> {stats.currentPeriod !== -1 ? stats.currentPeriod + 1 : 'None'}
            <span className="mx-2">|</span>
            <strong>Last Updated:</strong> {stats.time}
          </p>
          <table className="table table-bordered">
            <thead>
              <tr>
                <th>Room</th>
                <th>Free</th>
                <th>Class</th>
                <th>Section</th>
                <th>Subject</th>
                <th>Faculty</th>
              </tr>
            </thead>
            <tbody>
              {stats.result && stats.result.map((room, index) => (
                <tr key={index}>
                  <td>{room.room}</td>
                  <td>{room.free}</td>
                  <td>{room.class || '-'}</td>
                  <td>{room.sec || '-'}</td>
                  <td>{room.subject || '-'}</td>
                  <td>{room.faculty || '-'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
